            background: rgba(255, 252, 248, 0.82);
            color: var(--subtle);
        }
        .nav-user img {
            width: 34px;
            height: 34px;
            object-fit: cover;
            border-radius: 50%;
            border: 1px solid var(--line);
        }
        .hero, .card {
            background: var(--panel);
            border: 1px solid var(--line);
            border-radius: 18px;
            padding: 20px;
            box-shadow: 0 10px 30px rgba(98, 69, 49, 0.08);
            backdrop-filter: blur(6px);
        }
        .grid {
            display: grid;
            gap: 18px;
            grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
