<script>
    (() => {
        const fileInput = document.getElementById("avatar-file");
        const preview = document.getElementById("crop-preview");
        const cropLeft = document.getElementById("crop-left");
        const cropTop = document.getElementById("crop-top");
        const cropSize = document.getElementById("crop-size");
        if (!fileInput || !preview || !cropLeft || !cropTop || !cropSize) return;

        const updatePreview = () => {
            const x = Number(cropLeft.value) * 100;
            const y = Number(cropTop.value) * 100;
            const size = Number(cropSize.value);
            const zoom = 1 / size;
            preview.style.transform = `scale(${zoom})`;
            preview.style.transformOrigin = `${x}% ${y}%`;
        };

        fileInput.addEventListener("change", () => {
            const file = fileInput.files && fileInput.files[0];
            if (!file) return;
            preview.src = URL.createObjectURL(file);
            cropLeft.value = "0";
            cropTop.value = "0";
            cropSize.value = "1";
            updatePreview();
        });

        [cropLeft, cropTop, cropSize].forEach((element) => {
            element.addEventListener("input", updatePreview);
        });

        updatePreview();
    })();
</script>
